class Solution(object):
    def canPartitionGrid(self, grid):
        m, n = len(grid), len(grid[0])
        total = sum(sum(row) for row in grid)
        if total % 2 != 0:
            # Horizontal cuts
            prefix = 0
            for r in range(m - 1):
                prefix += sum(grid[r])
                if 2 * prefix == total:
                    return True
            # Vertical cuts
            col_sums = [sum(grid[r][c] for r in range(m)) for c in range(n)]
            prefix = 0
            for c in range(n - 1):
                prefix += col_sums[c]
                if 2 * prefix == total:
                    return True
            return False
